/**
 * Constrain a numeric value to the inclusive range [min, max].
 *
 * Throws:
 *  - TypeError if any argument is not a finite number (NaN or ±Infinity or non-number).
 *  - RangeError if min > max.
 */
export function clamp(value: number, min: number, max: number): number {
  // Defensive check: ensure exactly three args were provided to avoid surprising behavior
  if (arguments.length < 3) {
    throw new TypeError('clamp: requires value, min, and max arguments');
  }

  // Validate types and finiteness at runtime to provide clear errors.
  const isFiniteNumber = (x: unknown): x is number => typeof x === 'number' && Number.isFinite(x);

  if (!isFiniteNumber(value)) {
    throw new TypeError('clamp: value must be a finite number');
  }
  if (!isFiniteNumber(min)) {
    throw new TypeError('clamp: min must be a finite number');
  }
  if (!isFiniteNumber(max)) {
    throw new TypeError('clamp: max must be a finite number');
  }

  if (min > max) {
    throw new RangeError('clamp: min must be <= max');
  }

  if (value < min) return min;
  if (value > max) return max;
  return value;
}

/**
 * addNumbers: reliably add two numeric values with runtime validation.
 * - Throws TypeError if either argument is not a finite number.
 * - Throws RangeError if either argument's absolute value exceeds Number.MAX_SAFE_INTEGER.
 */
export function addNumbers(a: number, b: number): number {
  // Require two arguments so misuse is clearly signaled.
  if (arguments.length < 2) {
    throw new TypeError('addNumbers: requires two numeric arguments');
  }

  const isFiniteNumber = (x: unknown): x is number => typeof x === 'number' && Number.isFinite(x);

  if (!isFiniteNumber(a) || !isFiniteNumber(b)) {
    throw new TypeError('addNumbers: arguments must be finite numbers');
  }

  const max = Number.MAX_SAFE_INTEGER;
  if (Math.abs(a) > max || Math.abs(b) > max) {
    throw new RangeError('addNumbers: inputs must be within Number.MAX_SAFE_INTEGER in magnitude');
  }

  // Normal JS addition; IEEE-754 behavior is expected for floating point values.
  return a + b;
}

// Provide a short alias expected by tests.
export const add = addNumbers;


--- tests/index.test.ts ---
import { clampNumber } from '../src/index';

describe('clampNumber', () => {
  test('returns value when inside bounds', () => {
    expect(clampNumber(5, 1, 10)).toBe(5);
  });

  test('clamps value above max to max', () => {
    expect(clampNumber(15, 1, 10)).toBe(10);
  });

  test('clamps value below min to min', () => {
    expect(clampNumber(-5, 0, 10)).toBe(0);
  });

  test('min only clamps lower bound', () => {
    expect(clampNumber(2, 3)).toBe(3);
    expect(clampNumber(5, 3)).toBe(5);
  });

  test('max only clamps upper bound', () => {
    expect(clampNumber(8, undefined, 6)).toBe(6);
    expect(clampNumber(4, undefined, 6)).toBe(4);
  });

  test('throws when min > max', () => {
    expect(() => clampNumber(5, 10, 1)).toThrow(RangeError);
  });

  test('throws on non-finite value', () => {
    expect(() => clampNumber(NaN, 1, 2)).toThrow(TypeError);
    expect(() => clampNumber(Infinity)).toThrow(TypeError);
  });

  test('throws on non-finite min/max when provided', () => {
    expect(() => clampNumber(1, NaN)).toThrow(TypeError);
    expect(() => clampNumber(1, undefined, Infinity)).toThrow(TypeError);
  });
});


